#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel.  The whole function, including the
 * call and return, will be timed. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {

    // Use raw pointers for faster access – no bounds check.
    double *a = A.data();
    double *b = B.data();

    const double coeff = 0.33333;          // common constant
    const ptrdiff_t stride = 1;            // contiguous array

    // Work on interior sub‑array of size n-2; boundary elements stay unchanged.
    #pragma omp parallel for schedule(static)
    for (int t = 0; t < tsteps; ++t) {

        /* 1. Compute B[i] = coeff * (A[i-1] + A[i] + A[i+1]) */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            b[i] = coeff * (a[i-1] + a[i] + a[i+1]);
        }

        /* 2. Compute A[i] = coeff * (B[i-1] + B[i] + B[i+1]) */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n-1; ++i) {
            a[i] = coeff * (b[i-1] + b[i] + b[i+1]);
        }
    }
}
