#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {
    /*  Form  B := alpha*A**T*B.
        A is MxM (upper triangular part stored),
        B is MxN.                               */

    // Parallelise over rows of B
    #pragma omp parallel for schedule(static) default(none) \
        shared(m,n,alpha,A,B)
    for (int i = 0; i < m; ++i) {
        auto* Brow = B[i].data();                 // pointer to row i of B
        for (int j = 0; j < n; ++j) {
            double sum = 0.0;
            // A[k][i] is the (i,k) element of A^T = A^T_ik = A_ki
            for (int k = i + 1; k < m; ++k) {
                sum += A[k][i] * B[k][j];
            }
            Brow[j] = alpha * (Brow[j] + sum);
        }
    }
}
