/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    /* Convert the 2‑D vector into a flat 1‑D array for fast
       pointer arithmetic.  The data layout is row‑major, so
       A[i][j] == data[i*n + j].  The original vector structure
       is preserved, only the underlying buffer is accessed
       through a temporary pointer. */
    const int stride = n;
    #pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < n; ++i) {
        double* Ai = A[i].data();          // row i
        for (int j = 0; j < i; ++j) {
            double* Aij = Ai + j;          // address of A[i][j]
            double sum = *Aij;
            for (int k = 0; k < j; ++k)
                sum -= A[i][k] * A[k][j];
            *Aij = sum / A[j][j];
        }

        /* Upper part: i ≤ j < n   (no division needed) */
        for (int j = i; j < n; ++j) {
            double sum = Ai[j];
            for (int k = 0; k < i; ++k)
                sum -= A[i][k] * A[k][j];
            Ai[j] = sum;
        }
    }
}
