void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Ensure the inner vectors are contiguous
    int* data = &path[0][0];

    // Blocking parameters tuned for L2 cache (adjust if needed)
    const int B = 32;                 // block size
    const int Bn = (n + B - 1) / B;   // number of blocks

    // Main triple‑loop with cache blocking and OpenMP parallelisation
    for (int kk = 0; kk < Bn; ++kk) {
        int k = kk * B;
        int kMax = std::min(k + B, n);

        for (int ii = 0; ii < Bn; ++ii) {
            int i = ii * B;
            int iMax = std::min(i + B, n);

            // Parallelise over the outermost block (i dimension)
#pragma omp parallel for
            for (int iii = i; iii < iMax; ++iii) {
                int* row = data + iii * n;              // row i
                const int* rowK = data + k * n;          // row k
                for (int jj = 0; jj < n; ++jj) {
                    const int alt = rowK[k] + row[jj];
                    if (alt < row[jj]) row[jj] = alt;
                }
            }
        }
    }
}
