/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Use raw pointers for speed
    double *px = x.data();
    double *pb = b.data();

    // Main forward‑substitution loop
    for (int i = 0; i < n; ++i) {
        double val = pb[i];

        // vectorised inner loop: subtract L[i][j] * x[j]
        #pragma GCC ivdep
        for (int j = 0; j < i; ++j) {
            val -= L[i][j] * px[j];
        }

        // division by the diagonal element
        px[i] = val / L[i][i];
    }
}
