void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    const double inv_n   = 1.0 / n;
    const double inv_var = 1.0 / (n - 1.0);

    /* ---------- compute mean ---------- */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum * inv_n;
    }

    /* ---------- center the data ---------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        std::vector<double> const& row = data[i];
        std::vector<double>&       dst = data[i];
        for (int j = 0; j < m; ++j) dst[j] = row[j] - mean[j];
    }

    /* ---------- covariance matrix ---------- */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k)
                sum += data[k][i] * data[k][j];
            sum *= inv_var;
            cov[i][j] = sum;
            cov[j][i] = sum;          // symmetry
        }
    }
}
