/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
		    double alpha,
		    double beta,
		    std::vector<std::vector<double>>& A,
		    std::vector<std::vector<double>>& B,
		    std::vector<double>& tmp,
		    std::vector<double>& x,
		    std::vector<double>& y) {

    /* Parallelize over rows.  A naïve schedule static gives good
       load balance on a fixed n. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp_i = 0.0;
        double y_i   = 0.0;

        const double *Ai = A[i].data(); // row i of A
        const double *Bi = B[i].data(); // row i of B

        for (int j = 0; j < n; ++j) {
            double xj = x[j];
            tmp_i += Ai[j] * xj;
            y_i   += Bi[j] * xj;
        }

        tmp[i] = tmp_i;          // store intermediate result
        y[i]   = alpha * tmp_i + beta * y_i; // final combined expression
    }
}
