/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {

    // Launch outer loop in parallel; each iteration works on a distinct
    // row of A and therefore on a distinct element of x1/x2.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* rowA      = A[i].data();          // A[i][0 .. n-1]
        double* y1_ptr    = y_1.data();           // y_1[0 .. n-1]
        double* x1_ptr    = x1.data() + i;        // x1[i]
        double* x2_ptr    = x2.data() + i;        // x2[i]

        // Compute x1[i] += Σ_j A[i][j] * y_1[j]
        double sum1 = *x1_ptr;
        for (int j = 0; j < n; ++j)
            sum1 += rowA[j] * y1_ptr[j];
        *x1_ptr = sum1;

        // Compute x2[i] += Σ_j A[j][i] * y_2[j]
        double sum2 = *x2_ptr;
        double* y2_ptr = y_2.data();
        for (int j = 0; j < n; ++j)
            sum2 += A[j][i] * y2_ptr[j];
        *x2_ptr = sum2;
    }
}
