#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
                     std::vector<std::vector<double>>& A) {
    // Parallelise over the outer loop; each thread works on a distinct row `i`.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ai = A[i].data();          // Pointer to the i‑th row

        // Off‑diagonal entries (j < i)
        for (int j = 0; j < i; ++j) {
            double sum = Ai[j];            // start with the original value
            double* Aik = Ai;              // same as A[i]
            double* Ajk = A[j].data();     // row j

            // Compute Σ_k A[i][k] * A[j][k] for k < j
            for (int k = 0; k < j; ++k)
                sum -= Aik[k] * Ajk[k];

            Ai[j] = sum / Ajk[j];
        }

        // Diagonal entry A[i][i]
        double sum = Ai[i];
        for (int k = 0; k < i; ++k) {
            double v = Ai[k];
            sum -= v * v;
        }
        Ai[i] = std::sqrt(sum);
    }
}
