#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* Initialise y once. */
    #pragma omp parallel for
    for (int i = 0; i < n; ++i)
        y[i] = 0.0;

    /* Each thread works on a private copy of y and tmp. */
    int    num_threads = omp_get_max_threads();
    std::vector<std::vector<double>> y_local(num_threads, std::vector<double>(n, 0.0));
    std::vector<double>               tmp_local(num_threads, 0.0);

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        double* y_t = y_local[tid].data();
        double  *tmp_t = &tmp_local[tid];

        for (int i = 0; i < m; ++i) {
            *tmp_t = 0.0;
            for (int j = 0; j < n; ++j) {
                *tmp_t += A[i][j] * x[j];
            }

            for (int j = 0; j < n; ++j) {
                y_t[j] += A[i][j] * (*tmp_t);
            }
        }
    }

    /* Reduce thread‑local y into the global vector y. */
    #pragma omp parallel for
    for (int j = 0; j < n; ++j) {
        double accum = 0.0;
        for (int t = 0; t < num_threads; ++t)
            accum += y_local[t][j];
        y[j] = accum;
    }

    /* Copy back tmp from thread‑local copy (only the first thread is needed). */
    tmp.assign(tmp_local.begin(), tmp_local.end());
}
