#include <vector>
#include <cstring>
#include <immintrin.h>   // for potential SIMD intrinsics (used implicitly by GCC)

extern "C" void kernel_durbin(int n, std::vector<double>& r, std::vector<double>& y)
{
    // Internal workspace
    std::vector<double> z(n, 0.0);

    const double *Rp   = r.data();   // read‑only access to r
          double *Yp    = y.data();   // read/write access to y
          double *Zp    = z.data();

    /* --- Initialisation -------------------------------------------------- */
    Yp[0] = -Rp[0];
    double beta  = 1.0;
    double alpha = -Rp[0];

    /* --- Main loop ------------------------------------------------------- */
    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        /* 1. Compute the convolution sum.  */
        double sum = 0.0;
        #pragma omp simd reduction(+:sum)
        for (int i = 0; i < k; ++i) {
            sum += Rp[k - i - 1] * Yp[i];
        }

        /* 2. Update reflection coefficient. */
        alpha = -(Rp[k] + sum) / beta;

        /* 3. Compute new y[0..k-1] into z[0..k-1].  */
        #pragma omp simd
        for (int i = 0; i < k; ++i) {
            Zp[i] = Yp[i] + alpha * Yp[k - i - 1];
        }

        /* 4. Copy z back to y (k elements). */
        std::memcpy(Yp, Zp, k * sizeof(double));

        /* 5. Final element. */
        Yp[k] = alpha;
    }
}
