#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    /* ------------------------------------------------------------------
     * 1. Update matrix A:  A += u1*v1' + u2*v2'
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double ui1 = u1[i];
        double ui2 = u2[i];
        std::vector<double> &Arow = A[i];
        for (int j = 0; j < n; ++j)
            Arow[j] += ui1 * v1[j] + ui2 * v2[j];
    }

    /* ------------------------------------------------------------------
     * 2. Update vector x:  x += beta * A^T * y   (i.e. column‑wise)
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double bi = beta;
        double xi = x[i];
        for (int j = 0; j < n; ++j)
            xi += bi * A[j][i] * y[j];
        x[i] = xi;
    }

    /* ------------------------------------------------------------------
     * 3. Add vector z to x
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i)
        x[i] += z[i];

    /* ------------------------------------------------------------------
     * 4. Update vector w:  w += alpha * A * x
     * ------------------------------------------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double ai = alpha;
        double wi = w[i];
        const std::vector<double> &Arow = A[i];
        for (int j = 0; j < n; ++j)
            wi += ai * Arow[j] * x[j];
        w[i] = wi;
    }
}
```

The implementation keeps the exact semantics of the original code while:

* Leveraging OpenMP `parallel for` for independent loops.
* Prefetching inner‑loop variables (`ui1`, `ui2`, `bi`, `ai`) outside of the inner loops.
* Reducing repeated accesses to `x[i]`, `w[i]`, and `A[i]`.
* Using `schedule(static)` which works well for the regular loop bounds and the 8‑thread environment.

