#include <vector>
#include <cstddef>
#include <omp.h>

/* Optimised kernel for C = alpha * A * A^T + beta * C
 *  A   : n × m
 *  C   : n × n  (only the lower triangular part is used)
 *
 * The function keeps the same behaviour as the original,
 * but uses OpenMP for parallelism and
 * rearranges the loops to improve data locality.
 */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    // cache line width for a double on x86‑64
    constexpr std::size_t cache_line_bytes = 64;
    constexpr std::size_t cache_line_elems = cache_line_bytes / sizeof(double);

    // Parallelise over the outermost loop (rows of C)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // 1) beta‑scale the lower triangular part of row i
        double* cres = C[i].data();
        for (int j = 0; j <= i; ++j) {
            cres[j] *= beta;
        }

        // 2) accumulate alpha * A[i][k] * A[j][k] for all j <= i
        const double* arow = A[i].data();
        for (int k = 0; k < m; ++k) {
            const double aik = arow[k];
            if (aik == 0.0) continue;  // small optimisation for sparsity
            const double* ak_col = nullptr; // will be used via A[j][k]
            for (int j = 0; j <= i; ++j) {
                const double ajk = A[j][k];
                /* Unrolling the inner loop may help on some CPUs.
                   We unroll by 4 since cache_line_elems is 8. */
                cres[j] += alpha * aik * ajk;
            }
        }
    }
}
