// Optimised correlation kernel --------------------------------------------------
#include <algorithm>
#include <cmath>
#include <iostream>
#include <numeric>
#include <vector>
#include <omp.h>

#pragma omp declare target
inline double fast_sqrt(double x) { return std::sqrt(x); }
#pragma omp end declare target

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev) {
    const double eps = 0.1;
    const double invN  = 1.0 / static_cast<double>(n);
    const double invSqrtN = 1.0 / std::sqrt(static_cast<double>(n));

    /* ------------------------------------------------------------------------ */
    /* 1. Compute column means - parallel over columns                       */
    /* ------------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum * invN;
    }

    /* ------------------------------------------------------------------------ */
    /* 2. Compute stddev per column (variance first) - parallel over columns  */
    /* ------------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        const double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mu;
            s += d * d;
        }
        s = s * invN;
        s = std::sqrt(s);
        stddev[j] = (s <= eps ? 1.0 : s);
    }

    /* ------------------------------------------------------------------------ */
    /* 3. Standard‑normalise the data matrix                                  */
    /* ------------------------------------------------------------------------ */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        for (int j = 0; j < m; ++j) {
            row[j] = (row[j] - mean[j]) * (invSqrtN / stddev[j]);
        }
    }

    /* ------------------------------------------------------------------------ */
    /* 4. Compute correlation matrix (upper‑triangular)                        */
    /* ------------------------------------------------------------------------ */
#pragma omp parallel for schedule(dynamic)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;  // symmetry
        }
    }
    corr[m - 1][m - 1] = 1.0;
}
