#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_)
{
    /* Flatten the 2‑D structures locally for efficient access.
       The external signature must stay unchanged, so we only use
       temporary pointers. */
    double **exp = nullptr;
    double **eyp = nullptr;
    double **hzp = nullptr;

    /* Create raw pointers to the data of each inner vector. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < nx; ++i) {
        exp[i] = ex[i].data();
        eyp[i] = ey[i].data();
        hzp[i] = hz[i].data();
    }

    /* Main time loop */
    for (int t = 0; t < tmax; ++t) {
        /* 1. Apply the fictitious source to the first column of ey */
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < ny; ++j) {
            eyp[0][j] = _fict_[t];
        }

        /* 2. Update ey (i >= 1) */
