		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D,
		std::vector<std::vector<double>>& G)
{
    // ------------------------------------------------------------------
    // 1st matrix product:  E = A * B   (ni × nj = ni × nk * nk × nj)
    // ------------------------------------------------------------------
#pragma omp parallel for
    for (int i = 0; i < ni; ++i) {
        const double* restrict Ai = A[i].data();     // row i of A
        double* restrict Ei = E[i].data();          // row i of E

        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nk; ++k) {
                sum += Ai[k] * B[k][j];
            }
            Ei[j] = sum;
        }
    }

    // ------------------------------------------------------------------
    // 2nd matrix product:  F = C * D   (nj × nl = nj × nm * nm × nl)
    // ------------------------------------------------------------------
#pragma omp parallel for
    for (int i = 0; i < nj; ++i) {
        const double* restrict Ci = C[i].data();     // row i of C
        double* restrict Fi = F[i].data();           // row i of F

        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nm; ++k) {
                sum += Ci[k] * D[k][j];
            }
            Fi[j] = sum;
        }
    }

    // ------------------------------------------------------------------
    // 3rd matrix product:  G = E * F   (ni × nl = ni × nj * nj × nl)
    // ------------------------------------------------------------------
#pragma omp parallel for
    for (int i = 0; i < ni; ++i) {
        const double* restrict Ei = E[i].data();     // row i of E
        double* restrict Gi = G[i].data();           // row i of G

        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            for (int k = 0; k < nj; ++k) {
