#include <cmath>
#include <vector>
#include <cstddef>
#include <omp.h>

/* Convert std::vector<std::vector<T>> to a flat row‑major buffer  */
template <class T>
static void flatten(const std::vector<std::vector<T>>& src,
                    std::vector<T>& buf, std::size_t m, std::size_t n) {
    buf.resize(m * n);
    for (std::size_t i = 0; i < m; ++i)
        std::copy(src[i].begin(), src[i].end(), buf.begin() + i * n);
}

/* Convert a flat buffer back to a vector<vector<T>>                     */
template <class T>
static void unflatten(const std::vector<T>& buf,
                      std::vector<std::vector<T>>& dst,
                      std::size_t m, std::size_t n) {
    dst.resize(m);
    for (std::size_t i = 0; i < m; ++i) {
        dst[i].resize(n);
        std::copy(buf.begin() + i * n, buf.begin() + (i + 1) * n, dst[i].begin());
    }
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    /* Flatten matrices for contiguous access                           */
    std::vector<double> Abuf, Rbuf, Qbuf;
    flatten(A, Abuf, m, n);
    flatten(R, Rbuf, n, n);
    flatten(Q, Qbuf, m, n);

    /* Work locally on the buffers                                      */
    for (int k = 0; k < n; ++k) {
        double nrm = 0.0;

        /* Compute norm of column k of A */
#pragma omp simd reduction(+:nrm)
        for (int i = 0; i < m; ++i) {
            double a = Abuf[i * n + k];
            nrm += a * a;
        }
        Rbuf[k * n + k] = std::sqrt(nrm);

        /* Normalise column k to obtain Q's column */
#pragma omp parallel for simd
        for (int i = 0; i < m; ++i)
            Qbuf[i * n + k] = Abuf[i * n + k] / Rbuf[k * n + k];

        /* Update remaining columns                                */
        for (int j = k + 1; j < n; ++j) {
            double r = 0.0;
#pragma omp simd reduction(+:r)
            for (int i = 0; i < m; ++i)
                r += Qbuf[i * n + k] * Abuf[i * n + j];
            Rbuf[k * n + j] = r;

            /* A = A - Q(k) * r;  keep A as original matrix */
#pragma omp parallel for simd
            for (int i = 0; i < m; ++i)
                Abuf[i * n + j] -= Qbuf[i * n + k] * r;
        }
    }

    /* Unflatten results back into the original data structures      */
    unflatten(Abuf, A, m, n);
    unflatten(Rbuf, R, n, n);
    unflatten(Qbuf, Q, m, n);
}
