#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*
  Optimised version based on the original algorithm.
  It preserves exact behaviour while exploiting
  diagonal parallelism and a contiguous table layout.
*/

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table) noexcept
{
    // Flatten the 2‑D table into a 1‑D array for better cache locality.
    std::vector<int> flat(table.size() * n, 0);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[i * n + j] = table[i][j];

    auto match = [](int b1, int b2) -> int {
        return ((b1 + b2) == 3) ? 1 : 0;
    };

    // Process all diagonals d = j - i.  For each diagonal all cells
    // can be updated independently → perfect for parallelisation.
    for (int d = 1; d < n; ++d) {                      // distance between i and j
        #pragma omp parallel for schedule(static)
        for (int i = 0; i + d < n; ++i) {             // i is the row index
            int j = i + d;
            int idx = i * n + j;
            int best = flat[idx];                     // current value (might be 0)

            // Transition 1: skip [i]
            if (i + 1 < n) {
                best = std::max(best, flat[(i + 1) * n + j]);
            }

            // Transition 2: skip [j]
            if (j - 1 >= 0) {
                best = std::max(best, flat[i * n + (j - 1)]);
            }

            // Transition 3: match i and j
            if (i + 1 < j) {
                best = std::max(best, flat[(i + 1) * n + (j - 1)] + match(seq[i], seq[j]));
            } else {
                best = std::max(best, flat[(i + 1) * n + (j - 1)]);
            }

            // Transition 4: partition between k and k+1
            for (int k = i + 1; k < j; ++k) {
                int val = flat[i * n + k] + flat[(k + 1) * n + j];
                if (val > best) best = val;
            }
            flat[idx] = best;
        }
    }

    // Copy results back into the original 2‑D vector
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            table[i][j] = flat[i * n + j];
}
