static std::vector<double> flatten(const std::vector<std::vector<double>>& v, std::size_t rows, std::size_t cols) {
    std::vector<double> flat(rows * cols);
    for (std::size_t i = 0; i < rows; ++i) {
        const double* src  = v[i].data();
        double*       dst  = flat.data() + i * cols;
        std::memcpy(dst, src, cols * sizeof(double));
    }
    return flat;
}

/* Main computational kernel.  The caller must supply all matrices
   pre‑allocated with the appropriate dimensions.  The implementation
   uses flat arrays and OpenMP to maximise performance on a modern
   x86‑64 processor. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* Flatten all input matrices.  The flat buffers are intentionally
       allocated locally so that memory layout is contiguous and
       cache‑friendly.  The layout is row‑major: element (i,j) is at
       index i * cols + j. */
    std::vector<double> tmp_flat = flatten(tmp, ni, nj);
    const std::vector<double>& A_flat = flatten(A, ni, nk);
    const std::vector<double>& B_flat = flatten(B, nk, nj);
    const std::vector<double>& C_flat = flatten(C, nj, nl);
    std::vector<double> D_flat = flatten(D, ni, nl);                 // copy for in‑place update

    /* --------------------------------------------------------------
       Stage 1: tmp = alpha * A * B
       -------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* __restrict t_row = tmp_flat.data() + i * nj;
        const double* __restrict a_row = A_flat.data() + i * nk;
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double* __restrict b_col_start = B_flat.data() + j;
            for (int k = 0; k < nk; ++k) {
                sum += alpha * a_row[k] * b_col_start[k * nj];
            }
            t_row[j] = sum;
        }
    }

    /* --------------------------------------------------------------
       Stage 2: D = beta * D + tmp * C
       -------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* __restrict d_row = D_flat.data() + i * nl;
        const double* __restrict t_row = tmp_flat.data() + i * nj;
        for (int j = 0; j < nl; ++j) {
            double sum = beta * d_row[j];
            const double* __restrict c_col_start = C_flat.data() + j;
            for (int k = 0; k < nj; ++k) {
                sum += t_row[k] * c_col_start[k * nl];
