// --- Helper: linearize 2‑D vectors ---------------------------------------
// We keep the public signature, but inside we convert the 2‑D std::vector
// containers to single contiguous arrays so that the cache traffic is
// predictable and we can use range‑based loops with simple indexing.
//
// The caller allocates the 2‑D vectors with the proper sizes; all we need
// is a simple pointer into the underlying contiguous storage.
//
// We cannot change the interface, so all work is done via the original
// vector objects.  The performance win comes from using one–dimensional
// indexing, avoiding bound checks, and a single threaded access pattern.
//
// -------------------------------------------------------------------------

inline double* mat_data(std::vector<std::vector<double>>& M) {
    // The 2‑D vector must be contiguous: each row is allocated separately
    // but the outer vector stores pointers.  We cannot rely on that, so we
    // copy row pointers into a simple array.  This is O(N) and only paid
    // once per kernel invocation, which is negligible compared to the GEMM.
    static std::vector<double*> row_ptrs;
    row_ptrs.resize(M.size());
    for (size_t i = 0; i < M.size(); ++i)
        row_ptrs[i] = M[i].data();
    // The returned pointer is a fake; we use row_ptrs when indexing.
    // To keep code simple we actually return the first row pointer
    // and remember the stride (number of columns) externally.
    return row_ptrs.data();           // pointer to first element of row_ptrs
}

// -------------------------------------------------------------------------

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Precompute row pointers for the two input matrices
    const std::vector<double*> A_rows = [&]{
        std::vector<double*> r(ni);
        for (int i = 0; i < ni; ++i) r[i] = A[i].data();
        return r;
    }();

    const std::vector<double*> B_rows = [&]{
        std::vector<double*> r(nk);
        for (int k = 0; k < nk; ++k) r[k] = B[k].data();
        return r;
    }();

    // Work out column stride for B (assumes B is stored row‑major)
    const int B_col_stride = nj;

    // Transpose B into a contiguous buffer to improve spatial locality.
    // A BLAS GEMM typically accesses B columnwise, so this gives us
    // near‑perfect cache usage.  Allocation is on the stack for typical
    // matrix sizes but we use a vector for dynamic sizing.
    std::vector<double> B_t(nk * nj);   // B transposed: nj x nk
    for (int k = 0; k < nk; ++k) {
        double* src = B_rows[k];
        for (int j = 0; j < nj; ++j) {
            B_t[j * nk + k] = src[j];
        }
    }

    // Main kernel: parallel outer–loop over rows of C (and A).
    // Each thread works on a disjoint set of rows, ensuring no
    // false sharing.  We use OpenMP schedule(static) to keep the
    // rows balanced and to reduce the scheduling overhead.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* c_row = C[i].data();
        const double* a_row = A_rows[i];

        // Scale existing C by beta
        for (int j = 0; j < nj; ++j)
            c_row[j] *= beta;

        // Accumulate alpha * A[i, k] * B[k, j]
        for (int k = 0; k < nk; ++k) {
            double aik = alpha * a_row[k];
            // B_t is stored column‑wise, so B_t[j * nk + k] is B[k, j]
            for (int j = 0; j < nj; ++j)
                c_row[j] += aik * B_t[j * nk + k];
        }
    }
}
