/*
 * Optimised SYR2K kernel (lower triangular part only).
 * Keeps the exact observable behaviour of the original function
 * while exploiting contiguous memory accesses,
 * reducing bounds checks, and using OpenMP for parallelism.
 */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    constexpr std::size_t block = 32;        // Tuning parameter
    const double alph = alpha;                // Reduce look‑ups
    const double bet  = beta;

    /* Flatten access to the 2‑D std::vector by keeping row pointer cache. */
    const std::vector<double*> Cptr(n), Aptr(m), Bptr(m);
    for (int i = 0; i < n; ++i) Cptr[i] = C[i].data();
    for (int k = 0; k < m; ++k) Aptr[k] = A[k].data();
    for (int k = 0; k < m; ++k) Bptr[k] = B[k].data();

    /* Parallel over the rows of C. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* CI = Cptr[i];                 // pointer to row i of C
        const double* Ai = Aptr[i];           // row i of A
        const double* Bi = Bptr[i];           // row i of B

        /* Scale the lower triangle of C[i,:] by beta. */
        for (int j = 0; j <= i; ++j) {
            CI[j] *= bet;
        }

        /* For each column k in A and B accumulate A^T * B + B^T * A */
        for (int k = 0; k < m; ++k) {
            const double* Ak = Aptr[k];       // column k of A
            const double* Bk = Bptr[k];       // column k of B
            const double aik = Ai[k];
            const double bik = Bi[k];
            const double aikB = aik * alph;
            const double bikA = bik * alph;

            /* Compute inner loop over j with unrolling */
            int j = 0;
            for (; j <= i - block; j += block) {
                CI[j]   += Ak[j] * bik  * alph + Bk[j] * aik * alph;
                CI[j+1] += Ak[j+1] * bik * alph + Bk[j+1] * aik * alph;
                CI[j+2] += Ak[j+2] * bik * alph + Bk[j+2] * aik * alph;
                CI[j+3] += Ak[j+3] * bik * alph + Bk[j+3] * aik * alph;
                CI[j+4] += Ak[j+4] * bik * alph + Bk[j+4] * aik * alph;
                CI[j+5] += Ak[j+5] * bik * alph + Bk[j+5] * aik * alph;
                CI[j+6] += Ak[j+6] * bik * alph + Bk[j+6] * aik * alph;
                CI[j+7] += Ak[j+7] * bik * alph + Bk[j+7] * aik * alph;
            }
            for (; j <= i; ++j) {
                CI[j] += Ak[j] * bik * alph + Bk[j] * aik * alph;
            }
        }
    }
}
