 * A : 3‑D array stored as a flat vector
 * C4: 2‑D matrix stored as a flat vector
 * sum: temporary working vector
 *      (kept in the caller for memory reuse)
 *
 * The function preserves the exact semantics of the
 * original, but is rewritten for cache‑friendly
 * access, SIMD friendliness and OpenMP parallelism.
 */
static inline void kernel_doitgen_impl(
    std::size_t nr, std::size_t nq, std::size_t np,
    std::vector<double>& Aflat,         // flattened A[r][q][s]
    std::vector<double>& C4flat,        // flattened C4[s][p]
    double* const sum)                  // length np
{
    const std::size_t stride_rq = np;          // A[s] stride inside each slice
    const std::size_t stride_q  = np * np;     // A[s] stride between q's

    #pragma omp parallel for schedule(static)
    for (std::size_t r = 0; r < nr; ++r) {
        std::size_t base_r = r * stride_q;
        for (std::size_t q = 0; q < nq; ++q) {
            std::size_t base_rq = base_r + q * stride_rq;
            // compute sum for all p
            for (std::size_t p = 0; p < np; ++p) {
                double s = 0.0;
                double const* a_ptr = &Aflat[base_rq];
                double const* c_ptr = &C4flat[p];
                // vectorised inner product over s
                std::size_t s_idx = 0;
#pragma clang loop vectorize(enable)
#pragma GCC ivdep
                for (; s_idx + 4 <= np; s_idx += 4) {
                    s += a_ptr[s_idx]     * c_ptr[s_idx];
                    s += a_ptr[s_idx + 1] * c_ptr[s_idx + 1];
                    s += a_ptr[s_idx + 2] * c_ptr[s_idx + 2];
                    s += a_ptr[s_idx + 3] * c_ptr[s_idx + 3];
                }
                for (; s_idx < np; ++s_idx) {
                    s += a_ptr[s_idx] * c_ptr[s_idx];
                }
                sum[p] = s;
            }
            // write back the result to A
            std::memcpy(&Aflat[base_rq], sum, np * sizeof(double));
        }
    }
}

/* Public wrapper matching the original signature. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum)
{
    // flatten the 3‑D array A into a 1‑D vector for contiguous access
    std::vector<double> Aflat;
    Aflat.reserve(static_cast<std::size_t>(nr) * nq * np);
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            Aflat.insert(Aflat.end(),
                         A[r][q].begin(),
                         A[r][q].end());
        }
    }

    // flatten C4
    std::vector<double> C4flat;
    C4flat.reserve(static_cast<std::size_t>(np) * np);
    for (int s = 0; s < np; ++s) {
        C4flat.insert(C4flat.end(),
                      C4[s].begin(),
                      C4[s].end());
    }

    kernel_doitgen_impl(static_cast<std::size_t>(nr),
                        static_cast<std::size_t>(nq),
                        static_cast<std::size_t>(np),
                        Aflat, C4flat, sum.data());

    // copy back results to the original nested vectors
    std::size_t idx = 0;
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            std::copy(Aflat.begin() + idx,
                      Aflat.begin() + idx + np,
                      A[r][q].begin());
            idx += np;
        }
    }
}
