/* Optimised bicg kernel ----------------------------------------------------
 * The original kernel performs:
 *     s[j] = Σ_i r[i] * A[i][j]
 *     q[i] = Σ_j (A[i][j] + p[j])
 *
 * The optimised version:
 *   • Uses a row‑major flat view of the 2‑D vector for cache friendliness.
 *   • Adds an explicit pre‑computation of Σ_j p[j] (independent of i).
 *   • Employs OpenMP parallel loops with array reductions (supported by GCC 9+).
 *   • Avoids redundant memory access and keeps the same numeric results.
 * --------------------------------------------------------------------------*/

#include <vector>
#include <omp.h>

void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r) {

    /* Flatten A to a 1‑D view for contiguous iteration.
       We assume A is stored row‑major.                                           */
    const double* Aflat = reinterpret_cast<const double*>(A.data());

    /*------------------------------------------------------------*/
    /* 1. Compute s[j] = Σ_i r[i] * A[i][j]                       */
    /*------------------------------------------------------------*/
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i)
            sum += r[i] * Aflat[i * m + j];
        s[j] = sum;
    }

    /*------------------------------------------------------------*/
    /* 2. Compute q[i] = Σ_j (A[i][j] + p[j])                     */
    /*    The term Σ_j p[j] is independent of i and can be pre‑*/
    /*    computed once.                                           */
    /*------------------------------------------------------------*/
    double sum_p = 0.0;
#pragma omp parallel for reduction(+:sum_p)
    for (int j = 0; j < m; ++j)
        sum_p += p[j];

#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum_a = 0.0;
        for (int j = 0; j < m; ++j)
            sum_a += Aflat[i * m + j];
        q[i] = sum_a + sum_p;
    }
}
