#include <vector>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    const int inner  = n - 2;            // number of interior cells in one dimension
    const int stride1 = n * n;           // stride from [i][j][k] to [i+1][j][k]
    const int stride2 = n;               // stride from [i][j][k] to [i][j+1][k]
    const int stride3 = 1;               // stride from [i][j][k] to [i][j][k+1]

    // Flatten access functions
    auto idx = [=](int i, int j, int k) { return i * stride1 + j * stride2 + k * stride3; };

    // Flatten the 3‑D vectors into 1‑D arrays for faster access
    std::vector<double> flatA(n * n * n);
    std::vector<double> flatB(n * n * n);

    // Helper to copy 3‑D vector into flat array
    auto copy3Dto1D = [&](const std::vector<std::vector<std::vector<double>>>& src,
                          std::vector<double>& dst)
    {
        for (int i = 0; i < n; ++i)
            for (int j = 0; j < n; ++j)
                for (int k = 0; k < n; ++k)
                    dst[idx(i,j,k)] = src[i][j][k];
    };

    // Helper to copy 1‑D array back to 3‑D vector
    auto copy1Dto3D = [&](const std::vector<double>& src,
                          std::vector<std::vector<std::vector<double>>>& dst)
    {
        for (int i = 0; i < n; ++i)
            for (int j = 0; j < n; ++j)
                for (int k = 0; k < n; ++k)
                    dst[i][j][k] = src[idx(i,j,k)];
    };

    // Initial copy
    copy3Dto1D(A, flatA);
    copy3Dto1D(B, flatB);

    for (int t = 1; t <= tsteps; ++t) {
        /* Compute update from A -> B */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            int offset_i = idx(i,0,0);
            int offset_ip = idx(i+1,0,0);
            int offset_im = idx(i-1,0,0);
            for (int j = 1; j < n - 1; ++j) {
                int offset_j = offset_i + j * stride2;
                int offset_jp = offset_i + (j+1) * stride2;
                int offset_jm = offset_i + (j-1) * stride2;
                for (int k = 1; k < n - 1; ++k, ++offset_i, ++offset_ip, ++offset_im,
                                   ++offset_j, ++offset_jp, ++offset_jm, ++offset_i, ++offset_ip, ++offset_im,
                                   ++offset_j, ++offset_jp, ++offset_jm) {
                    double a    = flatA[offset_i];
                    double axp  = flatA[offset_ip];
                    double axm  = flatA[offset_im];
                    double ayp  = flatA[offset_jp];
                    double aym  = flatA[offset_jm];
                    double azp  = flatA[offset_i + stride3];
                    double azm  = flatA[offset_i - stride3];
                    flatB[offset_i] = 0.125 * (axp - 2.0 * a + axm) +
                                      0.125 * (ayp - 2.0 * a + aym) +
                                      0.125 * (azp - 2.0 * a + azm) + a;
                }
            }
        }

        /* Compute update from B -> A */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            int offset_i = idx(i,0,0);
            int offset_ip = idx(i+1,0,0);
            int offset_im = idx(i-1,0,0);
            for (int j = 1; j < n - 1; ++j) {
                int offset_j = offset_i + j * stride2;
                int offset_jp = offset_i + (j+1) * stride2;
                int offset_jm = offset_i + (j-1) * stride2;
                for (int k = 1; k < n - 1; ++k, ++offset_i, ++offset_ip, ++offset_im,
                                   ++offset_j, ++offset_jp, ++offset_jm) {
                    double b    = flatB[offset_i];
                    double bxp  = flatB[offset_ip];
                    double bxm  = flatB[offset_im];
                    double byp  = flatB[offset_jp];
                    double bym  = flatB[offset_jm];
                    double bzp  = flatB[offset_i + stride3];
                    double bzm  = flatB[offset_i - stride3];
                    flatA[offset_i] = 0.125 * (bxp - 2.0 * b + bxm) +
                                      0.125 * (byp - 2.0 * b + bym) +
                                      0.125 * (bzp - 2.0 * b + bzm) + b;
                }
            }
        }
    }

    // Copy back to original vectors
    copy1Dto3D(flatA, A);
    copy1Dto3D(flatB, B);
}
