```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;

    /* Pre‑compute constants used by the tridiagonal solves */
    const double mul1 = 2.0 * DT / (DX * DX);
    const double mul2 = 1.0 * DT / (DY * DY);

    const double a = -mul1 / 2.0;          // ( -B1*DT / (2*DX^2) )
    const double b = 1.0 + mul1;
    const double c = a;

    const double d = -mul2 / 2.0;          // ( -B2*DT / (2*DY^2) )
    const double e = 1.0 + mul2;
    const double f = d;

    /* Main time loop */
    for (int t = 1; t <= tsteps; ++t)
    {
        /* First sweep – compute v using current u */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double* v_row0 = v[0].data();
            double* p_row  = p[i].data();
            double* q_row  = q[i].data();

            v_row0[i]  = 1.0;          /* v[0][i] = 1.0 */
            p_row[0]   = 0.0;
            q_row[0]   = v_row0[i];

            /* Forward pass – tridiagonal solve for row i */
            for (int j = 1; j < n - 1; ++j)
            {
                const double denom = a * p_row[j - 1] + b;
                p_row[j] = -c / denom;

                const double ujmi1 = u[j][i - 1];
                const double ujm   = u[j][i];
                const double ujpi1 = u[j][i + 1];
                const double qjm   = q_row[j - 1];

                /* q[i][j] */
                q_row[j] = (-d * ujmi1 + (1.0 + 2.0 * d) * ujm
                            - f * ujpi1 - a * qjm) / denom;
            }

            v[n - 1][i] = 1.0;          /* v[n-1][i] = 1.0 */

            /* Backward pass – store v values */
            for (int j = n - 2; j >= 1; --j)
            {
                v[j][i] = p_row[j] * v[j + 1][i] + q_row[j];
            }
        }

        /* Second sweep – compute u using updated v */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double* u_row0 = u[0].data();      /* anyway not used but keep symmetry */
            double* p_row  = p[i].data();
            double* q_row  = q[i].data();

            u[i][0]       = 1.0;          /* u[i][0] = 1.0 */
            p_row[0]      = 0.0;
            q_row[0]      = u[i][0];

            /* Forward pass – tridiagonal solve for column i */
            for (int j = 1; j < n - 1; ++j)
            {
                const double denom = d * p_row[j - 1] + e;
                p_row[j] = -f / denom;

                const double vimj1 = v[i - 1][j];
                const double vimj  = v[i][j];
                const double vipj1 = v[i + 1][j];
                const double qjm   = q_row[j - 1];

                /* q[i][j] */
                q_row[j] = (-a * vimj1 + (1.0 + 2.0 * a) * vimj
                            - c * vipj1 - d * qjm) / denom;
            }

            u[i][n - 1] = 1.0;          /* u[i][n-1] = 1.0 */

            /* Backward pass – store u values */
            for (int j = n - 2; j >= 1; --j)
            {
                u[i][j] = p_row[j] * u[i][j + 1] + q_row[j];
            }
        }
    }
}
