#include <vector>
#include <cstddef>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A)
{
    // Local alias to avoid repeated operator[]
    std::vector<double*> row(n);
    for (int i = 0; i < n; ++i) row[i] = A[i].data();

    const double inv9 = 1.0 / 9.0;

    for (int t = 0; t < tsteps; ++t)
    {
        /* The stencil needs to read only values from the previous time
           step.  The original implementation updates A in-place
           row‑by‑row, left‑to‑right, so the updated values of the
           current row are never read by subsequent cells.  This
           behaviour is preserved by the following code.  */

        for (int i = 1; i <= n - 2; ++i)
        {
            const double* prev  = row[i-1];
            const double* cur   = row[i];
            const double* next  = row[i+1];

            double* out = cur;                // destination is the same row
            const double* prev_left  = prev;
            const double* prev_mid   = prev + 1;
            const double* prev_right = prev + 2;
            const double* next_left  = next;
            const double* next_mid   = next + 1;
            const double* next_right = next + 2;

            for (int j = 1; j <= n - 2; ++j)
            {
                /* Load the nine values contributing to the average */
                double s =
                    prev_left[j-1] + prev_mid[j-1] + prev_right[j-1] +
                    cur[j-1]          + cur[j]          + cur[j+1]  +
                    next_left[j-1]  + next_mid[j-1]  + next_right[j-1];

                out[j] = s * inv9;
            }
        }
    }
}
