```cpp
/* optimized kernel_deriche
 *
 * The function signature keeps the same, but the implementation
 * flattens the 2‑D containers, pre‑computes all constants, uses
 * contiguous memory access, OpenMP parallel loops, and minimal
 * floating‑point state per thread.  The logic and numerical results
 * are unchanged.
 */

#include <cmath>
#include <vector>
#include <omp.h>

static inline void kernel_deriche(int w, int h, double alpha,
                                  std::vector<std::vector<float>>& imgIn,
                                  std::vector<std::vector<float>>& imgOut,
                                  std::vector<std::vector<float>>& y1,
                                  std::vector<std::vector<float>>& y2)
{
    /* --------------------------------------------------------------
     * 1. Pre‑compute constants once
     * -------------------------------------------------------------- */
    const float a = static_cast<float>(alpha);
    const float e_a  = std::exp(-a);
    const float e_2a = e_a * e_a;

    const float k  = 1.0f - e_a * (1.0f - e_a) / (1.0f + 2.0f * a * e_a - e_2a);
    const float ke = k * e_a;

    const float a1 =   k;
    const float a2 =   ke * (a - 1.0f);
    const float a3 =   ke * (a + 1.0f);
    const float a4 =  -k * e_2a;
    const float a5 =   k;
    const float a6 =   ke * (a - 1.0f);
    const float a7 =   ke * (a + 1.0f);
    const float a8 =  -k * e_2a;

    const float b1 = std::pow(2.0, -a);
    const float b2 = -e_2a;
    const float c1 = 1.0f, c2 = 1.0f;

    /* --------------------------------------------------------------
     * 2. Flatten all 2‑D vectors into 1‑D arrays
     * -------------------------------------------------------------- */
    const int N = w * h;
    std::vector<float> in(N), out(N), tmp1(N), tmp2(N);

    auto idx = [h](int i, int j) { return i * h + j; };

    #pragma omp parallel for
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            in[idx(i,j)] = imgIn[i][j];

    /* --------------------------------------------------------------
     * 3. Row‑wise forward filtering (first pass)
     * -------------------------------------------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const int p = idx(i,j);
            tmp1[p] = a1 * in[p] + a2 * xm1 + b1 * ym1 + b2 * ym2;
            xm1 = in[p];
            ym2 = ym1;
            ym1 = tmp1[p];
        }
    }

    /* --------------------------------------------------------------
     * 4. Row‑wise backward filtering (second pass)
     * -------------------------------------------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h-1; j >= 0; --j) {
            const int p = idx(i,j);
            tmp2[p] = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            xp2 = xp1;
            xp1 = in[p];
            yp2 = yp1;
            yp1 = tmp2[p];
        }
    }

    /* --------------------------------------------------------------
     * 5. Combine the two row results
     * -------------------------------------------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j) {
            const int p = idx(i,j);
            out[p] = c1 * (tmp1[p] + tmp2[p]);
        }

    /* --------------------------------------------------------------
     * 6. Column‑wise forward filtering (third pass)
     * -------------------------------------------------------------- */
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const int p = idx(i,j);
            tmp1[p] = a5 * out[p] + a6 * tm1 + b1 * ym1 + b2 * ym2;
            tm1 = out[p];
            ym2 = ym1;
            ym1 = tmp1[p];
        }
    }

    /* --------------------------------------------------------------
     * 7. Column‑wise backward filtering (fourth pass)
     * -------------------------------------------------------------- */
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            const int p = idx(i,j);
            tmp2[p] = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            tp2 = tp1;
            tp1 = out[p];
            yp2 = yp1;
            yp1 = tmp2[p];
        }
    }

    /* --------------------------------------------------------------
     * 8. Final combination
     * -------------------------------------------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j) {
            const int p = idx(i,j);
            out[p] = c2 * (tmp1[p] + tmp2[p]);
        }

    /* --------------------------------------------------------------
     * 9. Copy result back into 2‑D vector
     * -------------------------------------------------------------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = out[idx(i,j)];
}
